// Decodificar e transformar dados de funcionários
const input = $input.first().json;
let data;

try {
  data = input.body?.data?.source?.itens;
  if (!data || !Array.isArray(data)) {
    throw new Error('Dados inválidos: esperado array em body.data.source.itens');
  }
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'employers_general_data',
    event: 'validation_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Dados inválidos', details: error.message }
  };
}

// Transformar dados de funcionários
const transformed = data.map(item => {
  // Função para formatar CPF
  const formatCPF = (cpf) => {
    if (!cpf) return '';
    return cpf.toString().replace(/\D/g, '').replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
  };

  // Função para parsear salário
  const parseSalary = (value) => {
    if (!value) return 0.0;
    let str = value.toString().replace(/[^\d,.-]/g, '');
    if (str.includes(',')) {
      str = str.replace(',', '.');
    }
    return parseFloat(str) || 0.0;
  };

  // Função para formatar data
  const formatDate = (dateStr) => {
    if (!dateStr) return null;
    try {
      // Assumindo formato dd/mm/yyyy
      const parts = dateStr.split('/');
      if (parts.length === 3) {
        return `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
      }
    } catch (e) {
      return null;
    }
    return null;
  };

  return {
    vhsys_id: parseInt(item.ID) || parseInt(item.vhsys_id) || 0,
    matricula: parseInt(item.matricula) || parseInt(item.Matricula) || 0,
    nome: item.nome || item.Nome || '',
    cargo: item.cargo || item.Cargo || '',
    cbo: item.cbo || item.CBO || '',
    rg: item.rg || item.RG || '',
    cpf: formatCPF(item.cpf || item.CPF),
    data_nascimento: formatDate(item.data_nascimento || item.DataNascimento),
    salario: parseSalary(item.salario || item.Salario),
    data_adm: formatDate(item.data_adm || item.DataAdmissao),
    data_dem: formatDate(item.data_dem || item.DataDemissao),
    status: item.status || item.Status || 'ativo',
    data_cad: formatDate(item.data_cad || item.DataCadastro),
    data_mod: formatDate(item.data_mod || item.DataModificacao),
    depto: item.depto || item.Departamento || ''
  };
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_general_data',
  event: 'data_transform_success',
  count: transformed.length,
  level: 'info'
}));

return { transformed };

// Sucesso
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_general_data',
  event: 'upsert_success',
  affected_rows: result.affectedRows || 0,
  level: 'info'
}));

return {
  statusCode: 201,
  body: { ok: true, message: 'Employers general data processed successfully' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_general_data',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process employers data' }
};
